impl Solution { pub fn min_swaps(nums: Vec<i32>) -> i32 { let digit_sum = |mut x: i32| { let mut s = 0; while x > 0 { s += x % 10; x /= 10; } s }; let mut black_pairs: Vec<(i32, i32, usize)> = nums.iter().enumerate().map(|(i, &x)| (digit_sum(x), x, i)).collect(); black_pairs.sort_unstable(); let mut black_vis = vec![false; nums.len()]; let mut black_ans = 0; for i in 0..nums.len() { if black_vis[i] || black_pairs[i].2 == i { continue; } let (mut curr, mut cycle) = (i, 0); while !black_vis[curr] { black_vis[curr] = true; curr = black_pairs[curr].2; cycle += 1; } black_ans += cycle - 1; } black_ans } }